import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [page, setPage] = useState('attendance'); 
  const [students, setStudents] = useState([]);
  const [search, setSearch] = useState('');

  const fetchStudents = () => {
    axios.get('http://localhost:3000/students').then(res => setStudents(res.data));
  };

  useEffect(() => { fetchStudents(); }, []);

  // Filter-ka Search-ka
  const filteredStudents = students.filter(s => 
    s.magaca.toLowerCase().includes(search.toLowerCase())
  );

  const markAttendance = async (id, status) => {
    await axios.post(`http://localhost:3000/attendance/${id}`, { xaadir: status });
    alert(status ? "√ Sax (Jooga)" : "X Qalad (Maqan)");
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Segoe UI' }}>
      {/* MENU-GA SARE */}
      <nav style={styles.nav}>
        <button onClick={() => setPage('home')} style={styles.btnNav}>🏠 Hoyga</button>
        <button onClick={() => setPage('attendance')} style={styles.btnNav}>📝 Xaadiriska</button>
      </nav>

      {page === 'attendance' && (
        <div style={styles.card}>
          <h2>Maamulka Xaadiriska</h2>
          {/* SEARCH BAR */}
          <input 
            style={styles.searchBar} 
            placeholder="Raadi magaca ardayga..." 
            onChange={(e) => setSearch(e.target.value)}
          />

          <table border="0" width="100%" style={{ borderCollapse: 'collapse', marginTop: '15px' }}>
            <thead>
              <tr style={{ background: '#34495e', color: 'white' }}>
                <th style={{ padding: '12px' }}>Magaca</th>
                <th>Fasalka</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {filteredStudents.map(std => (
                <tr key={std._id} style={{ borderBottom: '1px solid #ddd' }}>
                  <td style={{ padding: '12px' }}>{std.magaca}</td>
                  <td>{std.fasalka}</td>
                  <td>
                    <button style={styles.btnSax} onClick={() => markAttendance(std._id, true)}>√ Sax</button>
                    <button style={styles.btnQalad} onClick={() => markAttendance(std._id, false)}>X Qalad</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// QURXINTA (Styles)
const styles = {
  nav: { display: 'flex', gap: '10px', background: '#2c3e50', padding: '15px', borderRadius: '8px' },
  btnNav: { padding: '8px 20px', cursor: 'pointer', border: 'none', borderRadius: '5px' },
  card: { marginTop: '20px', padding: '20px', boxShadow: '0 4px 8px rgba(0,0,0,0.1)', borderRadius: '10px' },
  searchBar: { width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ccc', fontSize: '16px' },
  btnSax: { background: '#27ae60', color: 'white', border: 'none', padding: '6px 15px', borderRadius: '4px', cursor: 'pointer', marginRight: '5px' },
  btnQalad: { background: '#e74c3c', color: 'white', border: 'none', padding: '6px 15px', borderRadius: '4px', cursor: 'pointer' }
};

export default App;
